import requests

# Kong Admin API endpoint
KONG_ADMIN_API_ENDPOINT = 'http://localhost:8001'

def create_service(service_name, host):
    url = f'{KONG_ADMIN_API_ENDPOINT}/services'
    payload = {
        'name': service_name,
        'host': host
    }
    response = requests.post(url, json=payload)
    if response.status_code == 201:
        print(f'Service {service_name} created successfully')
    else:
        print(f'Failed to create service {service_name}')

def create_route(service_name):
    url = f'{KONG_ADMIN_API_ENDPOINT}/services/{service_name}/routes'
    payload = {
        'protocols': ['http', 'https'],
        'paths': ['/']
    }
    response = requests.post(url, json=payload)
    if response.status_code == 201:
        print(f'Route for service {service_name} created successfully')
    else:
        print(f'Failed to create route for service {service_name}')

def create_upstream(service_name):
    url = f'{KONG_ADMIN_API_ENDPOINT}/services/{service_name}/upstreams'
    payload = {
        'name': service_name,
        'algorithm': 'round-robin',
        'nodes': [
            {'id': 'node1', 'target': 'http://localhost:8000'}
        ]
    }
    response = requests.post(url, json=payload)
    if response.status_code == 201:
        print(f'Upstream for service {service_name} created successfully')
    else:
        print(f'Failed to create upstream for service {service_name}')

def main():
    # Create services
    create_service('my-service', 'localhost:8000')

    # Create routes
    create_route('my-service')

    # Create upstreams
    create_upstream('my-service')

if __name__ == '__main__':
    main()